// Ordena as mensagens pela data
items.sort((a, b) =>
  new Date(a.json.created_at).getTime() - new Date(b.json.created_at).getTime()
);

function formatarData(isoDate) {
  const d = new Date(isoDate);
  const dia = String(d.getDate()).padStart(2, "0");
  const mes = String(d.getMonth() + 1).padStart(2, "0");
  const ano = d.getFullYear();
  return `${dia}/${mes}/${ano}`;
}

const historico = [];

for (const item of items) {
  const row = item.json;
  const data = formatarData(row.created_at);

  if (row.mensagem_usuario?.trim()) {
    historico.push({
      autor: "Usuário",
      mensagem: row.mensagem_usuario.trim(),
      data
    });
  }

  if (row.mensagem_agente?.trim()) {
    historico.push({
      autor: "Agente",
      mensagem: row.mensagem_agente.trim(),
      data
    });
  }
}

return [{
  json: {
    historico_conversa: historico
  }
}];

const entrada = items[0].json;

let parameters = [];

switch (entrada.template) {
  case "confirmacao_presenca_1":
    // usa {{2}} → evento
    parameters = [
      { type: "text", text: String(entrada.var_2) }
    ];
    break;

  case "confirmacao_presenca_2":
    // usa {{1}} → evento
    parameters = [
      { type: "text", text: String(entrada.var_2) }
    ];
    break;

  case "confirmacao_presenca_3":
    // usa {{1}} → evento
    parameters = [
      { type: "text", text: String(entrada.var_2) }
    ];
    break;

  case "confirmacao_inscricao_chat_1":
  case "confirmacao_inscricao_chat_2":
    // usa {{1}} nome, {{2}} evento, {{3}} link
    parameters = [
      { type: "text", text: String(entrada.var_1) },
      { type: "text", text: String(entrada.var_2) },
      { type: "text", text: String(entrada.var_3) }
    ];
    break;
}

const body = {
  messaging_product: "whatsapp",
  to: String(entrada.telefone),
  type: "template",
  template: {
    name: entrada.template,
    language: { code: "pt_BR" },
    components: [
      {
        type: "body",
        parameters
      }
    ]
  }
};

return [{ json: { resultado: body } }];

return items.map(item => {
  let raw = item.json.output || "";
  let cleaned = raw;

  // Remove blocos de código
  cleaned = cleaned.replace(/```json/gi, "");
  cleaned = cleaned.replace(/```/g, "");
  cleaned = cleaned.trim();

  let respostaIA = {};

  try {
    respostaIA = JSON.parse(cleaned);
  } catch (e) {
    // fallback seguro
    respostaIA = {
      template: "confirmacao_presenca_1",
      var_1: item.json.name || "",
      var_2: item.json.nome_evento || "",
      var_3: item.json.link_landing_page || "",
      telefone: item.json.phone || ""
    };
  }

  // ✅ TEMPLATES SUPORTADOS (5)
  const templates = {
  confirmacao_presenca_1:
    "Oi! Tudo bem?\n\n" +
    "Estamos entrando em contato para confirmar seu interesse em participar do evento {{2}}.\n" +
    "Ficaremos muito felizes em ter você com a gente!\n\n" +
    "Para seguir no processo, é só acessar o link abaixo e preencher o formulário:\n" +
    "👉 {{3}}\n\n" +
    "Qualquer dúvida, é só responder essa mensagem!",

  confirmacao_presenca_2:
    "Oi! Passando rapidinho por aqui 😊\n\n" +
    "Ainda não identificamos sua inscrição no evento {{2}}.\n" +
    "Se ainda tiver interesse, é só acessar o link abaixo — o processo é rápido!\n\n" +
    "👉 {{3}}\n\n" +
    "Qualquer dúvida, estamos à disposição.",

  confirmacao_presenca_3:
    "Oi! Espero que esteja tudo certo por aí.\n\n" +
    "Passando para lembrar que o processo de inscrição para o evento {{2}} está em andamento.\n" +
    "Se ainda quiser participar, é só preencher o formulário no link abaixo:\n\n" +
    "👉 {{3}}\n\n" +
    "Fico à disposição caso precise de algo!",

  confirmacao_inscricao_1:
    "Oi, {{1}}! Tudo bem?\n\n" +
    "Estamos finalizando a etapa de inscrições para o evento {{2}} e queremos muito contar com seu interesse.\n\n" +
    "Para seguir no processo, é só acessar o link abaixo:\n" +
    "👉 {{3}}\n\n" +
    "O preenchimento é rápido! Fico no aguardo da sua inscrição.",

  confirmacao_inscricao_2:
    "Oi, {{1}}! Passando com um lembrete 😊\n\n" +
    "Você recebeu um convite para o evento {{2}} e o período de inscrições está avançando.\n\n" +
    "Se ainda tiver interesse, acesse o link oficial para se inscrever:\n" +
    "👉 {{3}}\n\n" +
    "Qualquer dúvida, é só responder por aqui!"
};

  const templateName = respostaIA.template;
  const textoTemplate =
    templates[templateName] || templates.confirmacao_presenca_1;

  // 🔁 Substituição das variáveis
  let mensagemFinal = textoTemplate
    .replace(/\{\{1\}\}/g, respostaIA.var_1 || "")
    .replace(/\{\{2\}\}/g, respostaIA.var_2 || "")
    .replace(/\{\{3\}\}/g, respostaIA.var_3 || "")


  return {
    json: {
      ...respostaIA,
      mensagem_template: mensagemFinal
    }
  };
});

